          <span style="font-size:.76rem;font-weight:700;padding:7px 13px;border-radius:8px;background:linear-gradient(135deg,#E84D3A,#8B5CF6);color:#fff;cursor:pointer" onclick="nav('gateway',{gateway:'stocks'})">Open StocksXX →</span>
