        <span style="font-size:.76rem;font-weight:700;padding:7px 13px;border-radius:8px;background:rgba(232,77,58,.08);color:#E85D3A;cursor:pointer" onclick="nav('gateway',{gateway:'climb'})">Watch in ClimbXX →</span>
