function showPurchase() {
  purchaseState = 'buy';
  renderModal();
  document.getElementById('purchaseModal').classList.add('show');
}

function renderModal() {
  const bz = BRAND_ZONES['la-sportiva'];
  const p = bz.products[0];
  let html;
  if (purchaseState === 'buy') {
    html = `<div class="modal">
      <div style="display:flex;gap:14px;margin-bottom:20px">
        <div style="width:90px;height:90px;border-radius:12px;background:linear-gradient(135deg,#3D2B1F,#2A1F18);display:flex;align-items:center;justify-content:center;font-size:2rem;flex-shrink:0">${p.emoji}</div>
        <div><h3>${p.name}</h3><p style="font-size:.82rem;opacity:.5">${p.desc}</p><div class="mprice" style="color:${bz.color}">${p.price}</div></div>
      </div>
      <div class="mdiv"></div>
      <div class="mlabel">Payment Method</div>
      <div class="mcard">💳 <span style="font-size:.86rem">Visa •••• 4821</span><span style="margin-left:auto;color:#4ADE80;font-weight:700">✓</span></div>
      <div class="mlabel">Delivery</div>
      <div class="mcard">📦 <span style="font-size:.86rem">Standard — 3-5 days</span></div>
      <button class="mbuy" style="background:${bz.color}" onclick="purchaseState='confirm';renderModal()">Buy Now — ${p.price}</button>
      <div class="mnote">Transaction processed by GENEXXO · Fulfilled by ${bz.name}<br>Supernova stored payment used across the ecosystem</div>
    </div>`;
  } else {
    html = `<div class="modal"><div class="modal-confirm">
      <div class="icon">✓</div>
      <h3>Purchase Complete</h3>
      <p>Your ${p.name} is on its way.<br>Fulfilment by ${bz.name}.</p>
      <p style="color:${bz.color};font-weight:600;font-size:.78rem;margin-top:6px">You're now part of ${bz.name}'s community — access support from your Hub.</p>
      <div class="done" onclick="document.getElementById('purchaseModal').classList.remove('show');nav('hub')">Return to Hub</div>
    </div></div>`;
  }
  document.getElementById('purchaseModal').innerHTML = html;
}

document.addEventListener('click', function(e) {
  const modal = document.getElementById('purchaseModal');
  if (modal && e.target === modal) modal.classList.remove('show');
});

function toggleWallet(gwKey, appName) {
  if (!wallet[gwKey]) wallet[gwKey] = [];
  const idx = wallet[gwKey].indexOf(appName);
  if (idx >= 0) wallet[gwKey].splice(idx, 1);
  else wallet[gwKey].push(appName);
  render();
}

